import { useMemo, useState } from 'react';

function Counter() {
    // Declare the count state
    const [count, setCount] = useState(0);

    // Memoize the count
    const memoizedCount = useMemo(() => {
        // Return the count
        return count;
    }, [count]);

    // Increment the count
    const increment = () => {
        setCount(count + 1);
    };

    // Render the component
    return (
        <div>
            <p>Count: {memoizedCount}</p>
            <button onClick={increment}>Increment</button>
        </div>
    );
}
